custom_overrides:
body, .page-container, .main-section {
  background-color: 
#0a1628 !important;
  color: 
#c4d4e8 !important;
  font-family: 'Inter', 'Segoe UI', sans-serif !important;
}
.navbar {
  background-color: 
#0d1e3a !important;
  border-bottom: 1px solid 
#1a2f52 !important;
}
.navbar a, .navbar .nav-link {
  color: 
#c9a84c !important;
}
.desk-sidebar, .layout-side-section {
  background-color: 
#0d1e3a !important;
  border-right: 1px solid 
#1a2f52 !important;
}
.sidebar-item a { color: 
#7a9bc4 !important; }
.sidebar-item.selected > a, .sidebar-item:hover > a {
  background-color: 
#1a3060 !important;
  color: 
#f0d080 !important;
  border-left: 2px solid 
#c9a84c !important;
}
.widget-card, .desk-card, .frappe-card,
.widget.shortcut-widget-box, .widget.links-widget-box {
  background-color: 
#0d1e3a !important;
  border: 1px solid 
#1a2f52 !important;
  border-radius: 10px !important;
}
.widget-title, .section-head, .form-section-heading {
  color: 
#c9a84c !important;
  font-weight: 600 !important;
}
.btn-primary {
  background-color: 
#c9a84c !important;
  color: 
#0d1e3a !important;
  border: none !important;
  font-weight: 600 !important;
}
.btn-primary:hover { background-color: 
#f0d080 !important; }
.form-control, .frappe-control input, .frappe-control select {
  background-color: 
#0a1628 !important;
  border: 1px solid 
#1a2f52 !important;
  color: 
#c4d4e8 !important;
  border-radius: 8px !important;
}
.datatable .dt-cell { color: 
#c4d4e8 !important; border-bottom: 1px solid 
#1a2f52 !important; }
.datatable .dt-header { background-color: 
#0d1e3a !important; color: 
#3d5a84 !important; }
.awesomplete, #navbar-search {
  background-color: 
#0d1e3a !important;
  border: 1px solid 
#1a2f52 !important;
  color: 
#c4d4e8 !important;
  border-radius: 8px !important;
}
/* Login page logo */
.login-content .for-login .page-card-head img,
.login-page img.website-image,
section.login-content img {
  max-width: 200px !important;
  height: auto !important;
  margin: 0 auto 16px auto !important;
  display: block !important;
  filter: brightness(1.1) !important;
}
/* Login card styling */
.for-login .page-card {
  background: 
#0d1e3a !important;
  border: 1px solid 
#1a2f52 !important;
  border-radius: 14px !important;
  box-shadow: 0 8px 32px rgba(0,0,0,0.4) !important;
}
/* Login title */
.login-content h4, .for-login h4,
.page-card-head .title {
  color: 
#c9a84c !important;
  font-weight: 600 !important;
  font-size: 18px !important;
  letter-spacing: 0.5px !important;
}
/* Input fields on login */
.for-login .form-control {
  background: 
#0a1628 !important;
  border: 1px solid 
#1a2f52 !important;
  color: 
#c4d4e8 !important;
  border-radius: 8px !important;
}

